logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class RedisConfig:
    REDIS_CLUSTER_NODES = os.getenv('REDIS_CLUSTER_NODES', 'localhost:7000,localhost:7001,localhost:7002')
    REDIS_SENTINEL_NODES = os.getenv('REDIS_SENTINEL_NODES', 'localhost:26379')
    REDIS_PASSWORD = os.getenv('REDIS_PASSWORD', '')
    REDIS_SSL = os.getenv('REDIS_SSL', 'false').lower() == 'true'
    REDIS_MODE = os.getenv('REDIS_MODE', 'cluster')
    
    SESSION_TOKEN_TTL = int(os.getenv('SESSION_TOKEN_TTL', 3600))
    API_KEY_TTL = int(os.getenv('API_KEY_TTL', 86400))
    REFRESH_TOKEN_TTL = int(os.getenv('REFRESH_TOKEN_TTL', 604800))


class RedisConnectionManager:
    def __init__(self, config: RedisConfig):
        self.config = config
        self.client = None
        self._connect()
    
    def _connect(self):
        try:
            if self.config.REDIS_MODE == 'cluster':
                self._connect_cluster()
            elif self.config.REDIS_MODE == 'sentinel':
                self._connect_sentinel()
            else:
                self._connect_standalone()
            logger.info(f"Successfully connected to Redis in {self.config.REDIS_MODE} mode")
        except Exception as e:
            logger.error(f"Failed to connect to Redis: {e}")
            raise
    
    def _connect_cluster(self):
        nodes = []
        for node in self.config.REDIS_CLUSTER_NODES.split(','):
            host, port = node.strip().split(':')
            nodes.append({'host': host, 'port': int(port)})
        
        self.client = RedisCluster(
            startup_nodes=nodes,
            decode_responses=True,
            password=self.config.REDIS_PASSWORD if self.config.REDIS_PASSWORD else None,
            ssl=self.config.REDIS_SSL,
            skip_full_coverage_check=True
        )
    
    def _connect_sentinel(self):
        sentinel_nodes = []
        for node in self.config.REDIS_SENTINEL_NODES.split(','):
            host, port = node.strip().split(':')
            sentinel_nodes.append((host, int(port)))
        
        sentinel = Sentinel(
            sentinel_nodes,
            socket_timeout=0.1,
            password=self.config.REDIS_PASSWORD if self.config.REDIS_PASSWORD else None
        )
        self.client = sentinel.master_for('mymaster', socket_timeout=0.1, decode_responses=True)
    
    def _connect_standalone(self):
        host, port = self.config.REDIS_CLUSTER_NODES.split(',')[0].strip().split(':')
        self.client = redis.Redis(
            host=host,
            port=int(port),
            password=self.config.REDIS_PASSWORD if self.config.REDIS_PASSWORD else None,
            decode_responses=True,
            ssl=self.config.REDIS_SSL
        )
    
    def get_client(self):
        return self.client


class SecureDataCache:
    def __init__(self, redis_client):
        self.redis = redis_client
        self.encryption_key = os.getenv('ENCRYPTION_KEY', secrets.token_hex(32))
    
    def _hash_key(self, key: str) -> str:
        return hashlib.sha256(key.encode()).hexdigest()
    
    def _encrypt_value(self, value: str) -> str:
        return hashlib.sha256(f"{value}{self.encryption_key}".encode()).hexdigest() + ":" + value
    
    def _decrypt_value(self, encrypted_value: str) -> str:
        if ":" not in encrypted_value:
            return encrypted_value
        hash_part, value = encrypted_value.split(":", 1)
        expected_hash = hashlib.sha256(f"{value}{self.encryption_key}".encode()).hexdigest()
        if hash_part == expected_hash:
            return value
        raise ValueError("Data integrity check failed")
    
    def store_session_token(self, user_id: str, session_token: str, ttl: Optional[int] = None) -> bool:
        try:
            key = f"session:{self._hash_key(user_id)}"
            encrypted_token = self._encrypt_value(session_token)
            ttl = ttl or RedisConfig.SESSION_TOKEN_TTL
            
            self.redis.setex(key, ttl, encrypted_token)
            
            self.redis.setex(
                f"session_metadata:{self._hash_key(user_id)}",
                ttl,
                json.dumps({
                    'user_id': user_id,
                    'created_at': str(timedelta(seconds=ttl))
                })
            )
            
            logger.info(f"Stored session token for user {user_id} with TTL {ttl}s")
            return True
        except Exception as e:
            logger.error(f"Error storing session token: {e}")
            return False
    
    def get_session_token(self, user_id: str) -> Optional[str]:
        try:
            key = f"session:{self._hash_key(user_id)}"
            encrypted_token = self.redis.get(key)
            
            if encrypted_token:
                return self._decrypt_value(encrypted_token)
            return None
        except Exception as e:
            logger.error(f"Error retrieving session token: {e}")
            return None
    
    def invalidate_session(self, user_id: str) -> bool:
        try:
            key = f"session:{self._hash_key(user_id)}"
            metadata_key = f"session_metadata:{self._hash_key(user_id)}"
            
            self.redis.delete(key, metadata_key)
            logger.info(f"Invalidated session for user {user_id}")
            return True
        except Exception as e:
            logger.error(f"Error invalidating session: {e}")
            return False
    
    def store_api_key(self, api_key_id: str, api_key: str, metadata: Dict[str, Any], ttl: Optional[int] = None) -> bool:
        try:
            key = f"apikey:{self._hash_key(api_key_id)}"
            encrypted_key = self._encrypt_value(api_key)
            ttl = ttl or RedisConfig.API_KEY_TTL
            
            pipe = self.redis.pipeline()
            pipe.setex(key, ttl, encrypted_key)
            pipe.setex(
                f"apikey_metadata:{self._hash_key(api_key_id)}",
                ttl,
                json.dumps(metadata)
            )
            pipe.execute()
            
            logger.info(f"Stored API key {api_key_id} with TTL {ttl}s")
            return True
        except Exception as e:
            logger.error(f"Error storing API key: {e}")
            return False
    
    def get_api_key(self, api_key_id: str) -> Optional[Dict[str, Any]]:
        try:
            key = f"apikey:{self._hash_key(api_key_id)}"
            metadata_key = f"apikey_metadata:{self._hash_key(api_key_id)}"
            
            pipe = self.redis.pipeline()
            pipe.get(key)
            pipe.get(metadata_key)
            encrypted_key, metadata_json = pipe.execute()
            
            if encrypted_key and metadata_json:
                return {
                    'api_key': self._decrypt_value(encrypted_key),
                    'metadata': json.loads(metadata_json)
                }
            return None
        except Exception as e:
            logger.error(f"Error retrieving API key: {e}")
            return None
    
    def revoke_api_key(self, api_key_id: str) -> bool:
        try:
            key = f"apikey:{self._hash_key(api_key_id)}"
            metadata_key = f"apikey_metadata:{self._hash_key(api_key_id)}"
            
            self.redis.delete(key, metadata_key)
            logger.info(f"Revoked API key {api_key_id}")
            return True
        except Exception as e:
            logger.error(f"Error revoking API key: {e}")
            return False
    
    def store_refresh_token(self, user_id: str, refresh_token: str, ttl: Optional[int] = None) -> bool:
        try:
            key = f"refresh:{self._hash_key(user_id)}"
            encrypted_token = self._encrypt_value(refresh_token)
            ttl = ttl or RedisConfig.REFRESH_TOKEN_TTL
            
            self.redis.setex(key, ttl, encrypted_token)
            logger.info(f"Stored refresh token for user {user_id} with TTL {ttl}s")
            return True
        except Exception as e:
            logger.error(f"Error storing refresh token: {e}")
            return False
    
    def get_refresh_token(self, user_id: str) -> Optional[str]:
        try:
            key = f"refresh:{self._hash_key(user_id)}"
            encrypted_token = self.redis.get(key)
            
            if encrypted_token:
                return self._decrypt_value(encrypted_token)
            return None
        except Exception as e:
            logger.error(f"Error retrieving refresh token: {e}")
            return None
    
    def invalidate_refresh_token(self, user_id: str) -> bool:
        try:
            key = f"refresh:{self._hash_key(user_id)}"
            self.redis.delete(key)
            logger.info(f"Invalidated refresh token for user {user_id}")
            return True
        except Exception as e:
            logger.error(f"Error invalidating refresh token: {e}")
            return False
    
    def extend_session_ttl(self, user_id: str, additional_ttl: int) -> bool:
        try:
            key = f"session:{self._hash_key(user_id)}"
            current_ttl = self.redis.ttl(key)
            
            if current_ttl > 0:
                new_ttl = current_ttl + additional_ttl
                self.redis.expire(key, new_ttl)
                self.redis.expire(f"session_metadata:{self._hash_key(user_id)}", new_ttl)
                logger.info(f"Extended session TTL for user {user_id} by {additional_ttl}s")
                return True
            return False
        except Exception as e:
            logger.error(f"Error extending session TTL: {e}")
            return False
    
    def get_session_ttl(self, user_id: str) -> int:
        try:
            key = f"session:{self._hash_key(user_id)}"
            return self.redis.ttl(key)
        except Exception as e:
            logger.error(f"Error getting session TTL: {e}")
            return -1


